var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"어? 이게 뭐야? 종신계약?","JPN":"え？　何なの、これ？　終身契約？","ENG":"Err? What's this? A lifetime contract?","TWN":"這？這是什麼？終身契約？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"좋아, 사인할게.","JPN":"いいよ、サインする。","ENG":"Sure, I'll sign it.","TWN":"好啊，那我就簽名吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"응? 괜찮아, 괜찮아! 나도 잘 생각해서 내린 결정이란 말씀!","JPN":"うん？　大丈夫、大丈夫！\\nちゃんと考えてから出した結論なんだから！","ENG":"Huh? Sure, why not? I've put enough thought into this already.","TWN":"嗯？沒問題，沒問題！我也是好好考慮過才這麼決定的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"있지, 사장님은 우리 아빠 때문에 비위 맞춰 주는 것도 아니면서 히어로가 되겠다고 할 때는 진지하게 받아들여 주잖아.","JPN":"ねえ、社長は私がヒーローになるって言い出すときは、いつも真剣に受け止めてくれるよね。","ENG":"You listened to me when I said I wanted to be a hero. You didn't do it because of my dad, either.","TWN":"聽好了，老闆又不是因為我爸才迎合我的。我說想當英雄的時候，您不是也很認真的聽進去了嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"사장님이랑 얘기하면서, 그동안 막연하게 생각했던 히어로란 뭔지 좀 더 선명해진 거 같아.","JPN":"社長と話してたら、今まで漠然と考えていたヒーローって何か、もっと鮮明になった気がするの。","ENG":"Talking to you has helped me clarify my vague idea of being a hero.","TWN":"和老闆聊過之後，英雄是什麼……直到那時都模糊不清的答案，似乎變得鮮明了起來。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"흔히 재벌가 사람들이 말하는, ‘날 이렇게 대한 사람은 네가 처음이야!’ 대충 그런 거지, 뭐!","JPN":"まぁ、お金持ちがよく言ってる「私にこんな態度を取る人はあなたが初めてだ！」みたいな感じかな！","ENG":"In other words, you're the first person who treated me this way, as cliche as it may sound.","TWN":"就像霸道總裁常對人說的“還是第一次有人敢這樣對我！”，大概是這種感覺吧！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"하하...... 다 털어 놓으니까 좀 쑥스럽다.","JPN":"はは……打ち解けたら、ちょっと恥ずかしいな。","ENG":"Hah hah... I feel a little bit embarrassed now that I told you the truth.","TWN":"哈哈……把自己的想法都說出來了，還真有點害羞呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"자, 잠깐만! 대답은 안 해도 돼! 어차피 우리는 말하지 않아도 정의로 한 마음이잖아?","JPN":"ま、待って！　返事しなくていいよ！\\nどうせ私たちは正義で結ばれてるから、同じ気持ちなんでしょう？","ENG":"Oh, please. You don't have to tell me what you think. You and I are bound to each other under justice, no matter what.","TWN":"等、等一下！不用回答我！反正我們就算不說出來，不也都是心向正義的夥伴嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"그럼 어서 계약서에 도장을......","JPN":"じゃあ、さっそく契約書にハンコを……","ENG":"Now, let me get my stamp to seal the deal...","TWN":"那就趕快在契約書上蓋章……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"아차! 도장, 도장 어디 뒀더라?","JPN":"あれ？　ハンコどこに置いたっけ？","ENG":"Err, my stamp. Where did I leave it?","TWN":"糟糕！印章，印章在哪呀？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};